import ast, sys

with open('myproject/myproject.py') as f:
    tree = ast.parse(f.read())

# Check for rx.State subclass with count: int = 0
for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef):
        for base in node.bases:
            if (isinstance(base, ast.Attribute) and base.attr == 'State') or \
               (isinstance(base, ast.Name) and base.id == 'State'):
                for item in node.body:
                    if isinstance(item, ast.AnnAssign) and isinstance(item.target, ast.Name) and item.target.id == 'count':
                        print(f'Found count: int = {ast.literal_eval(item.value) if item.value else None}')
                # Check methods
                for item in node.body:
                    if isinstance(item, ast.FunctionDef):
                        for stmt in ast.walk(item):
                            if isinstance(stmt, ast.AugAssign):
                                print(f'Found augmented assignment in {item.name}: self.count {type(stmt.op).__name__} {ast.unparse(stmt.value)}')
                            if isinstance(stmt, ast.Assign):
                                for target in stmt.targets:
                                    if isinstance(target, ast.Attribute) and target.attr == 'count':
                                        print(f'Found plain assignment in {item.name}: self.count = {ast.unparse(stmt.value)}')
                        # Check for parity var
                        if item.name == 'parity':
                            for decorator in item.decorator_list:
                                if isinstance(decorator, ast.Call):
                                    if isinstance(decorator.func, ast.Attribute) and decorator.func.attr == 'var':
                                        for kw in decorator.keywords:
                                            if kw.arg == 'cache' and isinstance(kw.value, ast.Constant) and kw.value.value is True:
                                                print('Found @rx.var(cache=True) on parity')
                        # Check returns
                        for stmt in ast.walk(item):
                            if isinstance(stmt, ast.Return) and isinstance(stmt.value, ast.Constant):
                                print(f'  parity returns literal: {stmt.value.value}')

# Check rx.cond usage
for node in ast.walk(tree):
    if isinstance(node, ast.Call):
        if isinstance(node.func, ast.Attribute) and node.func.attr == 'cond':
            print('Found rx.cond() call')

